import { describe, expect, it } from 'vitest';

import { createHfBpeMetaspaceTokenizer } from '../hf-tokenizer-json.ts';

// REGRESSION 2026-06-22 (gemma4-12b tokenizer bug):
// gemma4 was routed through the GPT-2 byte-BPE ('qwen2') loader, which
// byte-encodes spaces to `ń†` and merges against a vocab that never carries the
// `‚ĖĀ`-prefixed gemma tokens. The result was a high-vocab salad with the lone
// `ń†` token (id 245237 in the real gemma vocab) repeated at every word boundary
// and bare no-metaspace word variants (France=31756 instead of ‚ĖĀFrance=7001).
//
// The fix routes gemma through the SentencePiece-as-BPE metaspace path
// (createHfBpeMetaspaceTokenizer): a `Replace` normalizer maps space‚Üí`‚ĖĀ`,
// add_dummy_prefix prepends a leading `‚ĖĀ` to the first piece, and byte_fallback
// covers OOV. This test builds a gemma-shaped tokenizer.json (the same
// normalizer/pre_tokenizer/byte_fallback shape the real 262144 gemma vocab
// uses) and asserts the France probe tokenizes to the metaspace word ids ‚ÄĒ never
// a raw space token, never the no-metaspace variants.

// A minimal gemma-shaped tokenizer.json. Mirrors the real gemma export:
//   - model.type BPE, byte_fallback true, unk_token <unk>
//   - normalizer: Replace " " -> "‚ĖĀ"  (the metaspace marker)
//   - pre_tokenizer: Split (no-op for our purposes)
//   - merges that build the `‚ĖĀword` pieces from `‚ĖĀ` + letters
interface GemmaShapedTokenizerFixture {
  json: string;
  wordIds: number[];
  startOfTurnId: number;
  endOfTurnId: number;
  roleIds: Record<string, number>;
  ltCharId: number;
}

function buildGemmaShapedTokenizerJson(): GemmaShapedTokenizerFixture {
  const SPACE_TOKEN_ID = 9999; // the trap: a metaspace path must NEVER emit this
  const vocab: Record<string, number> = {
    '<unk>': 0,
    '<bos>': 1,
    '<eos>': 2,
    '‚ĖĀ': SPACE_TOKEN_ID, // bare metaspace token (the would-be "ń†" space-spam)
  };
  const merges: Array<[string, string]> = [];
  let nextId = 100;

  // Build each probe word as a `‚ĖĀword` metaspace token, assembled left-to-right
  // from `‚ĖĀ` + its chars via a strictly-ordered merge chain. Ranking each word's
  // chain contiguously (and earlier merges lower) makes greedy-by-rank BPE
  // assemble the full piece deterministically.
  const words = ['The', 'capital', 'of', 'France', 'is'];
  const wordIds: number[] = [];

  // single-char vocab entries (needed before any merge can fire)
  const allChars = new Set<string>(['‚ĖĀ']);
  for (const w of words) for (const c of w) allChars.add(c);
  for (const c of allChars) if (vocab[c] === undefined) vocab[c] = nextId++;

  for (const w of words) {
    // metaspace word token id
    const metaId = nextId++;
    vocab[`‚ĖĀ${w}`] = metaId;
    wordIds.push(metaId);
    // no-metaspace variant (the wrong-path trap) ‚ÄĒ distinct id. The GPT-2 byte
    // path would emit THIS (e.g. France) instead of the ‚ĖĀFrance metaspace token.
    vocab[w] = nextId++;

    // merge chain: `‚ĖĀ`+w[0], then accumulate the rest.
    let acc = `‚ĖĀ${w[0]}`;
    if (vocab[acc] === undefined) vocab[acc] = nextId++;
    merges.push(['‚ĖĀ', w[0]!]);
    for (let i = 1; i < w.length; i++) {
      const next = acc + w[i];
      if (vocab[next] === undefined) vocab[next] = nextId++;
      merges.push([acc, w[i]!]);
      acc = next;
    }
  }

  // Gemma's REAL chat markers. <start_of_turn>/<end_of_turn> are genuine special
  // tokens (ids 105/106 in the 262144 vocab) ‚ÄĒ they MUST be in added_tokens so
  // encodeBody matches them whole. `<|turn>`/`<|channel>` (the gemma4 template)
  // are NOT ‚ÄĒ to mimic the live tokenizer we register only the literal chars
  // (`<` `|` `turn` `>` `channel` ‚Ä¶) so those fake markers shred to char salad,
  // exactly as the real gemma vocab does (`<`=236820, `|`=236909, `>`=236813).
  const startOfTurnId = nextId++;
  vocab['<start_of_turn>'] = startOfTurnId;
  const endOfTurnId = nextId++;
  vocab['<end_of_turn>'] = endOfTurnId;
  const roleIds: Record<string, number> = {};
  for (const w of ['user', 'model']) {
    vocab[w] = vocab[w] ?? nextId++;
    roleIds[w] = vocab[w]!;
  }
  // Literal marker chars/words for the no-such-special-token fallback path.
  const lt = (vocab['<'] = nextId++); // stands in for live 236820
  vocab['|'] = nextId++;
  vocab['>'] = nextId++;
  vocab['turn'] = nextId++;
  vocab['channel'] = nextId++;
  vocab['thought'] = nextId++;
  vocab['\n'] = nextId++;

  // byte_fallback tokens (full coverage, like the real gemma vocab)
  for (let b = 0; b < 256; b++) {
    vocab[`<0x${b.toString(16).toUpperCase().padStart(2, '0')}>`] = nextId++;
  }

  const json = JSON.stringify({
    model: {
      type: 'BPE',
      vocab,
      merges,
      byte_fallback: true,
      unk_token: '<unk>',
    },
    normalizer: { type: 'Replace', pattern: { String: ' ' }, content: '‚ĖĀ' },
    pre_tokenizer: { type: 'Split', split: false },
    added_tokens: [
      { id: 1, content: '<bos>', special: true },
      { id: 2, content: '<eos>', special: true },
      { id: startOfTurnId, content: '<start_of_turn>', special: true },
      { id: endOfTurnId, content: '<end_of_turn>', special: true },
    ],
  });
  return { json, wordIds, startOfTurnId, endOfTurnId, roleIds, ltCharId: lt };
}

describe('gemma SentencePiece metaspace tokenizer (gemma4 France-probe regression)', () => {
  const { json, wordIds } = buildGemmaShapedTokenizerJson();
  const tok = createHfBpeMetaspaceTokenizer(json, 'gemma');
  const SPACE_TOKEN_ID = 9999;
  const PROBE = 'The capital of France is';

  it('tokenizes "The capital of France is" to the metaspace word ids', () => {
    // ‚ĖĀThe ‚ĖĀcapital ‚ĖĀof ‚ĖĀFrance ‚ĖĀis ‚ÄĒ one token per word, space folded into ‚ĖĀ.
    expect(tok.encode(PROBE, { addBos: false })).toEqual(wordIds);
  });

  it('never emits a bare space token (the 245237 / `ń†` space-spam from the qwen2 bug)', () => {
    expect(tok.encode(PROBE, { addBos: false })).not.toContain(SPACE_TOKEN_ID);
  });

  it('prepends BOS on encodePrompt and decodes the metaspace word ids back to text', () => {
    const ids = tok.encode(PROBE, { addBos: true });
    expect(ids).toEqual([1, ...wordIds]); // <bos> ‚ĖĀThe ‚ĖĀcapital ‚ĖĀof ‚ĖĀFrance ‚ĖĀis
    // decode strips <bos> (special) and maps ‚ĖĀ back to spaces (+ leading trim).
    expect(tok.decode(wordIds)).toBe(PROBE);
    expect(tok.decode(ids, { skipSpecial: true })).toBe(PROBE);
  });
});

// REGRESSION 2026-06-22 (gemma4-12b LIVE chat-template divergence):
// The metaspace tokenizer is correct, but the LIVE openai-server applied the
// `gemma4` chat template, which frames turns as `<|turn>‚Ä¶<turn|>` +
// `<|channel>thought<channel|>`. Those markers are NOT in the gemma 262144
// vocab (the ONLY tokenizer gemma4 loads). So encodeBody finds no matching
// special token and shreds each `<|turn>` into literal chars ‚ÄĒ the live garbage
// `236813(>) 12027(channel) 236820(<) ‚Ä¶ 887(turn) 236909(|)`. The DENSE-Gemma3
// forward (model_gemma4.rs: "registers gemma4-12b as architecture:'gemma3'‚Ä¶
// produces Paris") expects the gemma3 framing, whose markers ARE real special
// tokens: <start_of_turn>=105 / <end_of_turn>=106. The fix routes gemma4-12b/-31b
// to chatTemplate 'gemma'. This test proves the divergence on the SAME tokenizer:
// the gemma frame tokenizes clean (‚ĖĀFrance/‚ĖĀcapital survive, no `<` space-salad),
// the gemma4 frame produces the `<`-char garbage.
describe('gemma4 chat-template divergence (live 236xxx garbage regression)', () => {
  const { json, wordIds, startOfTurnId, endOfTurnId, ltCharId } =
    buildGemmaShapedTokenizerJson();
  const tok = createHfBpeMetaspaceTokenizer(json, 'gemma');
  const CONTENT = 'The capital of France is';
  const FRANCE_ID = wordIds[3]!; // ‚ĖĀFrance
  const CAPITAL_ID = wordIds[1]!; // ‚ĖĀcapital

  // Verbatim from openai-server.ts applyGemmaChatTemplate (the FIXED path).
  // <bos> is added by encode(addBos:true), not emitted literally.
  const gemmaFrame =
    `<start_of_turn>user\n${CONTENT}<end_of_turn>\n<start_of_turn>model\n`;
  // Verbatim from openai-server.ts applyGemma4ChatTemplate (the BROKEN path).
  const gemma4Frame =
    `<|turn>user\n${CONTENT}<turn|>\n<|turn>model\n<|channel>thought\n<channel|>`;

  it('gemma (<start_of_turn>) frame tokenizes the content with metaspace intact', () => {
    const ids = tok.encode(gemmaFrame, { addBos: true });
    // Real gemma turn markers are matched whole as special tokens, not shredded.
    expect(ids).toContain(startOfTurnId);
    expect(ids).toContain(endOfTurnId);
    // The capital / France content words keep their ‚ĖĀ metaspace.
    expect(ids).toContain(FRANCE_ID);
    expect(ids).toContain(CAPITAL_ID);
    // NO literal `<` char (the 236820-style space/marker-collapse) leaks in.
    expect(ids).not.toContain(ltCharId);
  });

  it('gemma4 (<|turn>) frame shreds the fake markers into `<`-char garbage', () => {
    const ids = tok.encode(gemma4Frame, { addBos: true });
    // `<|turn>` is not a vocab token ‚Üí falls to the literal `<` char (live 236820).
    expect(ids).toContain(ltCharId);
    // This is precisely why gemma4-12b/-31b must NOT use chatTemplate 'gemma4'.
  });
});
